447:     static AuthorizationResult findResult(Action action,
448:                                           AuthorizableRequestContext requestContext,
449:                                           StandardAcl acl) {
450:         return findResult(
451:             action,
452:             matchingPrincipals(requestContext),
453:             requestContext.clientAddress().getHostAddress(),
454:             acl
