593:     private static class MatchingRuleBuilder {
594:         private static final DefaultRule DENY_RULE = new DefaultRule(DENIED);
595:         private final DefaultRule noAclRule;
596:         private StandardAcl denyAcl;
597:         private StandardAcl allowAcl;
598:         private boolean hasResourceAcls;
599: 
600:         public MatchingRuleBuilder(DefaultRule noAclRule) {
601:             this.noAclRule = noAclRule;
602:         }
603: 
604:         boolean foundDeny() {
605:             return denyAcl != null;
606:         }
607: 
608:         MatchingRule build() {
609:             if (denyAcl != null) {
610:                 return new MatchingAclRule(denyAcl, DENIED);
611:             } else if (allowAcl != null) {
612:                 return new MatchingAclRule(allowAcl, ALLOWED);
613:             } else if (!hasResourceAcls) {
614:                 return noAclRule;
615:             } else {
616:                 return DENY_RULE;
617:             }
618:         }
619:     }
